149→export const computeSectorKey = (x, y, sectorSize = 2000) => {
150→    const fx = toFiniteNumber(x);
151→    const fy = toFiniteNumber(y);
152→    const size = Math.max(1, Number(sectorSize) || 2000);
153→    if (fx == null || fy == null) return null;
154→
155→    const sx = Math.floor(fx / size);
156→    const sy = Math.floor(fy / size);
157→    return `${sx}:${sy}`;
158→};
159→
160→export const getNeighborSectorKeys = (centerKey) => {
161→    if (typeof centerKey !== 'string') return [];
162→    const [sxRaw, syRaw] = centerKey.split(':');
163→    const sx = Number(sxRaw);
164→    const sy = Number(syRaw);
165→    if (!Number.isFinite(sx) || !Number.isFinite(sy)) return [];
166→
167→    const keys = [];
168→    for (let dy = -1; dy <= 1; dy++) {
169→        for (let dx = -1; dx <= 1; dx++) {
170→            keys.push(`${sx + dx}:${sy + dy}`);
171→        }
172→    }
173→    return keys;
174→};
175→
176→export const buildSectorIndex = (items, getCoords, sectorSize = 2000) => {
177→    const index = new Map();
178→    if (!Array.isArray(items) || typeof getCoords !== 'function') return index;
179→
180→    for (const item of items) {
181→        const coords = getCoords(item);
182→        if (!coords) continue;
183→        const key = computeSectorKey(coords.x, coords.y, sectorSize);
184→        if (!key) continue;
185→
186→        if (!index.has(key)) index.set(key, []);
187→        index.get(key).push(item);
188→    }
189→
190→    return index;
191→};
192→
193→export const computeGalaxySimilarityEdges = (
194→    centroidByUser,
195→    activeUserIds,
196→    threshold = 0.3,
197→    maxEdges = 500
198→) => {
199→    if (!(centroidByUser instanceof Map) || centroidByUser.size < 2) return [];
200→
201→    const users = activeUserIds
202→        ? Array.from(activeUserIds).filter((id) => centroidByUser.has(id))
203→        : Array.from(centroidByUser.keys());
204→
205→    if (users.length < 2) return [];
206→
207→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.3;
208→    const edges = [];
209→
210→    for (let i = 0; i < users.length; i++) {
211→        for (let j = i + 1; j < users.length; j++) {
212→            const userA = users[i];
213→            const userB = users[j];
214→            const sim = cosineSimilarity(centroidByUser.get(userA), centroidByUser.get(userB));
215→            if (sim >= minSimilarity) {
216→                edges.push({ user_a: userA, user_b: userB, similarity: sim });
217→            }
218→        }
219→    }
220→
221→    edges.sort((a, b) => b.similarity - a.similarity);
222→    const limit = normalizeMaxEdges(maxEdges, 500);
223→    return edges.length > limit ? edges.slice(0, limit) : edges;
224→};
225→
226→const clampOffsetMagnitude = (offset, maxOffset) => {
227→    const limit = Math.max(0, Number(maxOffset) || 0);
228→    if (limit === 0) return { dx: 0, dy: 0 };
229→
230→    const mag = Math.sqrt(offset.dx * offset.dx + offset.dy * offset.dy);
231→    if (mag <= limit || mag <= EPSILON) return offset;
232→
233→    return {
234→        dx: (offset.dx / mag) * limit,
235→        dy: (offset.dy / mag) * limit,
236→    };
237→};
238→
239→export const computeGalaxyForces = (positions, targets, edges, options = {}) => {
240→    const forces = new Map();
241→    if (!(positions instanceof Map) || positions.size === 0) return forces;
242→
243→    const springK = Number.isFinite(Number(options.springK)) ? Number(options.springK) : 0.06;
244→    const edgeStrength = Number.isFinite(Number(options.edgeStrength)) ? Number(options.edgeStrength) : 0.0004;
245→    const idealDistanceScale = Number.isFinite(Number(options.idealDistanceScale))
246→        ? Number(options.idealDistanceScale)
247→        : 3000;
248→    const repulsion = Number.isFinite(Number(options.repulsion)) ? Number(options.repulsion) : 3e6;
249→    const maxRepulsionDistance = Number.isFinite(Number(options.maxRepulsionDistance))
250→        ? Number(options.maxRepulsionDistance)
251→        : 10000;
252→
253→    const activeIds = options.activeIds
254→        ? new Set(Array.from(options.activeIds).filter((id) => positions.has(id)))
255→        : new Set(positions.keys());
256→    const ids = Array.from(activeIds);
257→    if (ids.length === 0) return forces;
258→
259→    for (const id of ids) {
260→        forces.set(id, { fx: 0, fy: 0 });
261→    }
262→
263→    // 1) Spring toward targets (used as fallback when server targets exist).
264→    if (targets instanceof Map && targets.size > 0) {
265→        for (const id of ids) {
266→            const pos = positions.get(id);
267→            const target = targets.get(id);
268→            if (!pos || !target) continue;
269→            const f = forces.get(id);
270→            f.fx += (target.x - pos.x) * springK;
271→            f.fy += (target.y - pos.y) * springK;
272→        }
273→    }
274→
275→    // 2) Similarity edges.
276→    if (Array.isArray(edges) && edges.length > 0) {
277→        for (const edge of edges) {
278→            const userA = edge?.user_a;
279→            const userB = edge?.user_b;
280→            if (!activeIds.has(userA) || !activeIds.has(userB)) continue;
281→
282→            const posA = positions.get(userA);
283→            const posB = positions.get(userB);
284→            if (!posA || !posB) continue;
285→
286→            const fA = forces.get(userA);
287→            const fB = forces.get(userB);
288→            if (!fA || !fB) continue;
289→
290→            const similarity = clamp(Number(edge?.similarity) || 0, -1, 1);
291→            const dx = posB.x - posA.x;
292→            const dy = posB.y - posA.y;
293→            const distSq = Math.max(dx * dx + dy * dy, 1);
294→            const dist = Math.sqrt(distSq);
295→            const idealDist = idealDistanceScale * (1 - Math.max(0, similarity));
296→            const strength = Math.max(0, similarity) * edgeStrength * (dist - idealDist);
297→            const fx = (dx / dist) * strength;
298→            const fy = (dy / dist) * strength;
299→
300→            fA.fx += fx;
301→            fA.fy += fy;
302→            fB.fx -= fx;
303→            fB.fy -= fy;
304→        }
305→    }
306→
307→    // 3) Pairwise repulsion.
308→    const maxRepulsionDistanceSq = maxRepulsionDistance * maxRepulsionDistance;
309→    for (let i = 0; i < ids.length; i++) {
310→        for (let j = i + 1; j < ids.length; j++) {
311→            const a = positions.get(ids[i]);
312→            const b = positions.get(ids[j]);
313→            if (!a || !b) continue;
314→
315→            const dx = b.x - a.x;
316→            const dy = b.y - a.y;
317→            const distSqRaw = dx * dx + dy * dy;
318→            if (!Number.isFinite(distSqRaw) || distSqRaw > maxRepulsionDistanceSq) continue;
319→
320→            const distSq = Math.max(distSqRaw, 1);
321→            const dist = Math.sqrt(distSq);
322→            const force = repulsion / distSq;
323→            const fx = (dx / dist) * force;
324→            const fy = (dy / dist) * force;
325→
326→            const fA = forces.get(ids[i]);
327→            const fB = forces.get(ids[j]);
328→            fA.fx -= fx;
329→            fA.fy -= fy;
330→            fB.fx += fx;
331→            fB.fy += fy;
332→        }
333→    }
334→
335→    return forces;
336→};
337→
338→export const computeStarPullOffsets = (
339→    starPulls,
340→    galaxyTargets,
341→    starBases,
342→    pullStrength = 120,
343→    maxOffset = 80
344→) => {
345→    const offsets = new Map();
346→    if (!Array.isArray(starPulls) || starPulls.length === 0) return offsets;
347→    if (!(galaxyTargets instanceof Map) || !(starBases instanceof Map)) return offsets;
348→
349→    const resolvedPullStrength = Number.isFinite(Number(pullStrength)) ? Number(pullStrength) : 120;
350→
351→    for (const pull of starPulls) {
352→        const postId = pull?.post_id;
353→        const galaxyId = pull?.galaxy_user_id;
354→        const similarity = Number(pull?.similarity);
355→        if (!postId || !galaxyId || !Number.isFinite(similarity) || similarity <= 0.4) continue;
356→
357→        const galaxy = galaxyTargets.get(galaxyId);
358→        const base = starBases.get(postId);
359→        if (!galaxy || !base) continue;
360→
361→        const dx = galaxy.x - base.x;
362→        const dy = galaxy.y - base.y;
363→        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
364→
365→        const strength = (similarity - 0.4) * resolvedPullStrength;
366→        const fx = (dx / dist) * strength;
367→        const fy = (dy / dist) * strength;
368→
369→        if (!offsets.has(postId)) {
370→            offsets.set(postId, { dx: 0, dy: 0 });
371→        }
372→        const offset = offsets.get(postId);
373→        offset.dx += fx;
374→        offset.dy += fy;
375→    }
376→
377→    for (const [postId, offset] of offsets.entries()) {
378→        offsets.set(postId, clampOffsetMagnitude(offset, maxOffset));
379→    }
380→
381→    return offsets;
382→};
383→
384→export const computeStarPullOffsetsFromEmbeddings = ({
385→    posts = [],
386→    galaxyCentroids = new Map(),
387→    galaxyPositions = new Map(),
388→    activePostIds = null,
389→    activeGalaxyIds = null,
390→    minSimilarity = 0.4,
391→    pullStrength = 120,
392→    maxOffset = 80,
393→    maxGalaxyLinks = 6,
394→} = {}) => {
395→    const offsets = new Map();
396→    if (!Array.isArray(posts) || posts.length === 0) return offsets;
397→    if (!(galaxyCentroids instanceof Map) || galaxyCentroids.size === 0) return offsets;
398→    if (!(galaxyPositions instanceof Map) || galaxyPositions.size === 0) return offsets;
399→
400→    const minSim = Number.isFinite(Number(minSimilarity)) ? Number(minSimilarity) : 0.4;
401→    const resolvedPullStrength = Number.isFinite(Number(pullStrength)) ? Number(pullStrength) : 120;
402→    const topGalaxyLimit = normalizeMaxEdges(maxGalaxyLinks, 6);
403→
404→    const galaxyIds = activeGalaxyIds
405→        ? Array.from(activeGalaxyIds).filter((id) => galaxyCentroids.has(id) && galaxyPositions.has(id))
406→        : Array.from(galaxyCentroids.keys()).filter((id) => galaxyPositions.has(id));
407→
408→    if (galaxyIds.length === 0) return offsets;
409→
410→    for (const post of posts) {
411→        const postId = post?.id;
412→        if (!postId) continue;
413→        if (activePostIds && !activePostIds.has(postId)) continue;
414→
415→        const ownerId = post?.users?.id ?? post?.user_id;
416→        const postEmbedding = normalizeEmbedding(post?.embeddings);
417→        if (!postEmbedding) continue;
418→
419→        const baseX = toFiniteNumber(post?.universe_x) ?? toFiniteNumber(post?.display_x);
420→        const baseY = toFiniteNumber(post?.universe_y) ?? toFiniteNumber(post?.display_y);
421→        if (baseX == null || baseY == null) continue;
422→
423→        const candidates = [];
424→        for (const galaxyId of galaxyIds) {
425→            if (!galaxyId || galaxyId === ownerId) continue;
426→
427→            const centroidEmbedding = galaxyCentroids.get(galaxyId);
428→            const galaxyPos = galaxyPositions.get(galaxyId);
429→            if (!centroidEmbedding || !galaxyPos) continue;
430→
431→            const sim = cosineSimilarity(postEmbedding, centroidEmbedding);
432→            if (sim < minSim) continue;
433→
434→            candidates.push({ sim, galaxyPos });
435→        }
436→
437→        if (candidates.length === 0) continue;
438→        candidates.sort((a, b) => b.sim - a.sim);
439→
440→        let dxSum = 0;
441→        let dySum = 0;
442→        const limit = Math.min(candidates.length, topGalaxyLimit);
443→        for (let i = 0; i < limit; i++) {
444→            const { sim, galaxyPos } = candidates[i];
445→            const dx = galaxyPos.x - baseX;
446→            const dy = galaxyPos.y - baseY;
447→            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
448→            const strength = (sim - minSim) * resolvedPullStrength;
449→            dxSum += (dx / dist) * strength;
450→            dySum += (dy / dist) * strength;
451→        }
452→
453→        offsets.set(postId, clampOffsetMagnitude({ dx: dxSum, dy: dySum }, maxOffset));
454→    }
455→
456→    return offsets;
457→};
458→
459→export const computeSemanticBridges = (
460→    posts,
461→    computedStarPositions,
462→    threshold = 0.9,
463→    maxPairs = 120
464→) => {
465→    if (!Array.isArray(posts) || posts.length < 2) return [];
466→    if (!(computedStarPositions instanceof Map)) return [];
467→
468→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.9;
469→    const limit = normalizeMaxEdges(maxPairs, 120);
470→
471→    const enriched = [];
472→    for (const post of posts) {
473→        const postId = post?.id;
474→        if (!postId || !computedStarPositions.has(postId)) continue;
475→        const embedding = normalizeEmbedding(post?.embeddings);
476→        if (!embedding) continue;
477→        enriched.push({ postId, embedding });
478→    }
479→
480→    if (enriched.length < 2) return [];
481→
482→    const pairs = [];
483→    for (let i = 0; i < enriched.length; i++) {
484→        for (let j = i + 1; j < enriched.length; j++) {
485→            const similarity = cosineSimilarity(enriched[i].embedding, enriched[j].embedding);
486→            if (similarity > minSimilarity) {
487→                pairs.push({
488→                    post_a: enriched[i].postId,
489→                    post_b: enriched[j].postId,
490→                    similarity,
491→                });
492→            }
493→        }
494→    }
495→
496→    pairs.sort((a, b) => b.similarity - a.similarity);
497→    return pairs.length > limit ? pairs.slice(0, limit) : pairs;
498→};
