 73→        const breathe = 1.0 + 0.25 * Math.sin(time * 0.001 + phaseOffset);
 74→        const r = radius * breathe;
 75→
 76→        // Large pulsing outer halo — makes it unmissable
 77→        const pulseScale = 1.0 + 0.3 * Math.sin(time * 0.0015 + phaseOffset);
 78→        const haloR = r * 4.0 * pulseScale;
 79→        const haloGrad = ctx.createRadialGradient(x, y, 0, x, y, haloR);
 80→        haloGrad.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.25 * opacity})`);
 81→        haloGrad.addColorStop(0.3, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.12 * opacity})`);
 82→        haloGrad.addColorStop(0.6, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.04 * opacity})`);
 83→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
 84→        ctx.beginPath();
 85→        ctx.arc(x, y, haloR, 0, TWO_PI);
 86→        ctx.fillStyle = haloGrad;
 87→        ctx.fill();
 88→
 89→        // Inner bright glow
 90→        const innerGlow = ctx.createRadialGradient(x, y, 0, x, y, r * 1.8);
 91→        innerGlow.addColorStop(0, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.45 * opacity})`);
 92→        innerGlow.addColorStop(0.4, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.2 * opacity})`);
 93→        innerGlow.addColorStop(1, 'rgba(0,0,0,0)');
 94→        ctx.beginPath();
 95→        ctx.arc(x, y, r * 1.8, 0, TWO_PI);
 96→        ctx.fillStyle = innerGlow;
 97→        ctx.fill();
 98→
 99→        // Dark center void (the "hole")
100→        const voidGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.4);
101→        voidGrad.addColorStop(0, `rgba(0,0,0,${0.85 * opacity})`);
102→        voidGrad.addColorStop(0.6, `rgba(0,0,0,${0.4 * opacity})`);
103→        voidGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.beginPath();
105→        ctx.arc(x, y, r * 0.4, 0, TWO_PI);
106→        ctx.fillStyle = voidGrad;
107→        ctx.fill();
108→
109→        // Bright event horizon ring
110→        const ehRadius = r * 0.48;
111→        const ehAlpha = (0.6 + 0.2 * Math.sin(time * 0.002 + phaseOffset)) * opacity;
