### Phase 3: New File -- `client/src/components/Universe/hooks/useStarPhysics.js`

**Purpose:** The main React hook that owns the Matter.js engine, manages body lifecycle, applies forces each frame, and exposes body positions to the rendering layer.

This is the most complex new file. Key responsibilities:
1. Create/destroy Matter engine on mount/unmount.
2. Sync star bodies with `activePostIds` (create, sleep, destroy).
3. Apply semantic forces + anchor forces every frame.
4. Manage constellation constraints from `similarPairs`.
5. Handle star drag interactions.
6. Push body positions to React state periodically.

```javascript
// useStarPhysics.js -- Hook signature and key logic

export default function useStarPhysics({
    posts,                  // full post array (Map values)
    activePostIds,          // Set<postId> from sector partitioning
    galaxyPositions,        // Map<userId, {x, y}> from useCosmicGravity
    starPulls,              // server data: [{post_id, galaxy_user_id, similarity}]
    similarPairs,           // server data: [{post_a, post_b, similarity}]
    isGalaxySettled,        // boolean from useCosmicGravity
    enabled,                // kill switch for the entire physics system
}) {
    // Returns:
    // {
    //     starBodyPositions: Map<postId, {x, y}>,  // current physics positions
    //     isStarDragging: React.RefObject<boolean>, // for camera hook coordination
    //     startStarDrag: (postId, worldX, worldY) => void,
    //     updateStarDrag: (worldX, worldY) => void,
    //     endStarDrag: () => void,
    //     getStarVelocity: (postId) => {vx, vy} | null,
    // }
}
```

**Internal state management:**

```
Refs (mutable, not triggering re-renders):
  - engineRef: the Matter.Engine instance
  - bodyMapRef: Map<postId, Matter.Body>
  - constraintMapRef: Map<"postA:postB", Matter.Constraint>
  - semanticMapsRef: {starPullMap, pairMap} from buildSemanticMaps()
  - anchorTargetsRef: Map<postId, {x, y}> -- updated each frame from galaxyPositions
  - dragConstraintRef: current drag constraint (or null)
  - lastDestroyCheckRef: timestamp for periodic cleanup
  - frameCountRef: for RENDER_EVERY throttling

State (triggers re-renders):
  - starBodyPositions: Map<postId, {x, y}> -- pushed every RENDER_EVERY frames
```

**RAF loop pseudocode:**

```
function tick(timestamp) {
    if (!enabled) return;

    // 1. Update anchor targets from latest galaxyPositions
    updateAnchorTargets(posts, galaxyPositions, bodyMapRef);

    // 2. Apply forces to each active body
    for (const [postId, body] of bodyMapRef) {
        if (body.isSleeping || body.isStatic) continue;

        // Galaxy anchor force (soft spring toward galaxy position + local offset)
        const anchor = anchorTargetsRef.get(postId);
        if (anchor) {
            const f = computeAnchorForce(body.position, anchor, PHYSICS_CONFIG.anchorSpringK);
            Body.applyForce(body, body.position, { x: f.fx, y: f.fy });
        }

        // Cross-galaxy semantic pull
        const pull = computeSemanticPullForce(
            body.position, postId, semanticMapsRef.starPullMap,
            galaxyPositions, PHYSICS_CONFIG.semanticPullK
        );
        Body.applyForce(body, body.position, { x: pull.fx, y: pull.fy });
    }

    // 3. Step the engine
    Engine.update(engineRef.current, 1000 / 60);  // fixed timestep

    // 4. Push positions to React (throttled)
    frameCountRef.current++;
    if (frameCountRef.current % RENDER_EVERY === 0) {
        const positions = new Map();
        for (const [postId, body] of bodyMapRef) {
            positions.set(postId, { x: body.position.x, y: body.position.y });
        }
        setStarBodyPositions(positions);
    }

    // 5. Periodic cleanup of stale static bodies
    if (timestamp - lastDestroyCheckRef.current > 10000) {
        destroyStaleBodies();
        lastDestroyCheckRef.current = timestamp;
    }

    rafRef.current = requestAnimationFrame(tick);
}
```

**Body lifecycle effect:**

```javascript
useEffect(() => {
    const currentBodies = bodyMapRef.current;
    const engine = engineRef.current;
    if (!engine) return;

    // Create bodies for new active posts
    for (const postId of activePostIds) {
        if (currentBodies.has(postId)) {
            // Already exists -- ensure it's not static
            const body = currentBodies.get(postId);
            if (body.isStatic) {
                Body.setStatic(body, false);
                Sleeping.set(body, false);
            }
            continue;
        }

        const post = postMap.get(postId);  // need a Map version of posts
        if (!post) continue;

        // Compute initial position using existing static formula
        const pos = computeInitialStarPosition(post, galaxyPositions);
        if (!pos) continue;

        const radius = getStarRadius(post.like_count ?? 0);
        const mass = getStarMass(post.like_count ?? 0);
        const body = createStarBody(postId, pos.x, pos.y, radius, mass);

        World.add(engine.world, body);
        currentBodies.set(postId, body);
    }

    // Sleep bodies that are no longer active
    for (const [postId, body] of currentBodies) {
        if (!activePostIds.has(postId) && !body.isStatic) {
            Body.setStatic(body, true);
        }
    }
}, [activePostIds]);
```

**Constraint sync effect:**

```javascript
useEffect(() => {
    // Rebuild constraints when similarPairs changes
    // Remove old constraints
    for (const [key, constraint] of constraintMapRef.current) {
        World.remove(engineRef.current.world, constraint);
    }
    constraintMapRef.current.clear();

    // Create new constraints for active pairs
    if (!Array.isArray(similarPairs)) return;

    for (const pair of similarPairs) {
        const bodyA = bodyMapRef.current.get(pair.post_a);
        const bodyB = bodyMapRef.current.get(pair.post_b);
        if (!bodyA || !bodyB) continue;

        const constraint = createConstellationConstraint(bodyA, bodyB, pair.similarity);
        World.add(engineRef.current.world, constraint);
        constraintMapRef.current.set(`${pair.post_a}:${pair.post_b}`, constraint);
    }
}, [similarPairs, activePostIds]);
