### Phase 8: Coordinate Conversion Utility

**New helper in `client/src/components/Universe/utils/coordConversion.js`:**

The physics drag needs to convert screen pixel coordinates to world coordinates. This depends on `camera`, `zoom`, and `stageSize`.

```javascript
/**
 * Convert screen (pixel) coordinates to world coordinates.
 * Inverse of the Konva layer transform at parallax factor 1.0.
 */
export function screenToWorld(screenX, screenY, camera, zoom, stageSize) {
    return {
        x: camera.x + (screenX - stageSize.width / 2) / zoom,
        y: camera.y + (screenY - stageSize.height / 2) / zoom,
    };
}

/**
 * Convert world coordinates to screen (pixel) coordinates.
 */
export function worldToScreen(worldX, worldY, camera, zoom, stageSize) {
    return {
        x: (worldX - camera.x) * zoom + stageSize.width / 2,
        y: (worldY - camera.y) * zoom + stageSize.height / 2,
    };
}
```

